// Parse and validate quote request data
const data = $input.first().json;

// Normalize field names (form may send various formats)
const firstName = data.first_name || data.firstName || data.fname || '';
const lastName = data.last_name || data.lastName || data.lname || '';
const email = data.email || data.email_address || '';
const phone = data.phone || data.phone_number || data.tel || '';
const state = (data.state || data.us_state || '').toUpperCase().substring(0, 2);
const coverageType = (data.coverage_type || data.coverage || data.type || 'health').toLowerCase();
const coverageAmount = data.coverage_amount || data.coverageAmount || data.loan_amount || 0;
const birthDate = data.birth_date || data.birthDate || data.dob || '';
const age = birthDate ? Math.floor((new Date() - new Date(birthDate)) / (365.25 * 24 * 60 * 60 * 1000)) : 0;

// Validate required fields
const errors = [];
if (!firstName) errors.push('Missing first name');
if (!email) errors.push('Missing email');
if (!phone) errors.push('Missing phone');

// Check licensed states (FL, TX, CA, NC, SC, MI)
const licensedStates = ['FL', 'TX', 'CA', 'NC', 'SC', 'MI'];
const isLicensedState = licensedStates.includes(state);

// Determine coverage type
let coverageLabel = 'Health Insurance';
if (coverageType.includes('life')) coverageLabel = 'Life Insurance';
else if (coverageType.includes('medicare')) coverageLabel = 'Medicare';
else if (coverageType.includes('final') || coverageType.includes('expense')) coverageLabel = 'Final Expense';
else if (coverageType.includes('supplement')) coverageLabel = 'Medicare Supplement';

return {
  firstName, lastName, email, phone, state, coverageType,
  coverageAmount, birthDate, age, coverageLabel,
  isLicensedState, hasErrors: errors.length > 0, errors,
  fullName: `${firstName} ${lastName}`.trim(),
  source: 'quote_form',
  originalData: data
};

